+  { command: `cmd1 || cmd2 | cmd3` },
+  { command: "cmd\targ" },
+  { command: `cmd '' ` },
+  { command: `cmd "" ` },
+  { command: `cmd 'incomplete` },
+  { command: `cmd "incomplete` },
+  { command: `cmd --flag=` },
+  { command: `cmd --flag=''` },
+  { command: `cmd --flag=""` },
+  { command: `cmd -f=''` },
+  { command: `cmd 'hello' "world" ` },
+  { command: `cmd "it's" ` },
+  { command: `cmd "a"b "c"d` },
+  { command: "cmd C:\\Users\\dir\\file", shell: Shell.Powershell },
+  { command: "cmd dir\\ name/file", shell: Shell.Bash },
+  { command: "cmd dir` name/file", shell: Shell.Pwsh },
+  { command: "cmd dir^ name/file", shell: Shell.Cmd },
+  { command: "cmd --flag value", shell: Shell.Nushell },
+  { command: "cmd --flag value", shell: Shell.Fish },
+  { command: "cmd --flag value", shell: Shell.Xonsh },
+  { command: "cmd `n`t arg", shell: Shell.Powershell },
 ];

 describe(`parseCommand`, () => {
   testData.forEach(({ command, shell }) => {
-    test(command, () => {
+    test(`[${shell ?? "bash"}] ${command}`, () => {
       expect(parseCommand(command, shell ?? Shell.Bash)).toMatchSnapshot();
     });
   });
 });
+
+describe(`multi-shell whitespace escaping`, () => {
+  const shellEscapeData: { shell: Shell; command: string }[] = [
+    { shell: Shell.Bash, command: `cmd dir\\ name` },
+    { shell: Shell.Zsh, command: `cmd dir\\ name` },
+    { shell: Shell.Pwsh, command: "cmd dir` name" },
+    { shell: Shell.Powershell, command: "cmd dir` name" },
+    { shell: Shell.Cmd, command: `cmd dir^ name` },
+    { shell: Shell.Fish, command: `cmd dir\\ name` },
+    { shell: Shell.Xonsh, command: `cmd dir\\ name` },
+    { shell: Shell.Nushell, command: `cmd dir\\ name` },
+  ];
+
+  shellEscapeData.forEach(({ shell, command }) => {
+    test(`[${shell}] escaped space: ${command}`, () => {
+      const tokens = parseCommand(command, shell);
+      expect(tokens).toMatchSnapshot();
+      expect(tokens.at(-1)?.token).toContain(" ");
+    });
+  });
+});

diff --git a/src/tests/isterm/pty.test.ts b/src/tests/isterm/pty.test.ts
new file mode 100644
index 0000000..6a5cd92
--- /dev/null
+++ b/src/tests/isterm/pty.test.ts
@@ -0,0 +1,67 @@
+// Copyright (c) Microsoft Corporation.
+// Licensed under the MIT License.
+
+import os from "node:os";
+import isterm from "../../isterm";
+import { cursorBackward } from "../../utils/ansi";
+import { Shell } from "../../utils/bindings";
+
+const windowsTest = os.platform() == "win32" ? test : test.skip;
+
+const runTerm = async (shell: Shell, input: string[], env?: { [key: string]: string | undefined }) => {
+  const ptyProcess = isterm.spawn({ shell, rows: process.stdout.rows, cols: process.stdout.columns, env });
+  await new Promise((r) => setTimeout(r, 1_000));
+  for (const data of input) {
+    ptyProcess.write(data);
+    await new Promise((r) => setTimeout(r, 1_500));
+  }
+  const commandState = ptyProcess.getCommandState();
+  const hasPromptText = commandState.promptText != null;
+  delete commandState.promptText;
+  return { ...commandState, hasPromptText };
+};
+
+windowsTest(
+  "test cmd on initial simple command input",
+  async () => {
+    const r = await runTerm(Shell.Cmd, ["dir"]);
+    expect(r).toMatchSnapshot();
+  },
+  10000,
+);
+
+windowsTest(
+  "test cmd on initial simple command input with cursor movement backward",
+  async () => {
+    const r = await runTerm(Shell.Cmd, ["dir" + cursorBackward(1)]);
+    expect(r).toMatchSnapshot();
+  },
+  10000,
+);
+
+windowsTest(
+  "test cmd on multi line command input",
+  async () => {
+    const r = await runTerm(Shell.Cmd, ["dir\r", "cmd"]);
+    expect(r).toMatchSnapshot();
+  },
+  10000,
+);
+
+windowsTest(
+  "test powershell on suggestion detection",
+  async () => {
+    const r = await runTerm(Shell.Pwsh, ["ls -Force\r", "ls"]);
+    expect(r).toMatchSnapshot();
+  },
+  10000,
+);
+
+windowsTest(
+  "test powershell on command detection after failure",
+  async () => {
+    const r = await runTerm(Shell.Pwsh, ["tomato\r", "zsh"]);
+    expect(r).toMatchSnapshot();
+  },
+  10000,
+);

